/**
 * Facebook MAIN world: patch `fetch` / `XHR` for Facebook hosts only, clone matching responses,
 * and hand bodies to {@link ./facebook-intercept-extract.ts} (GraphQL + same-tab document/HTML).
 */

import {
    processDocumentResponseBody,
    processGraphQlResponseBody,
} from './facebook-intercept-extract';
import './facebook-intercept-types';

export type { WirePlayableRow, WireVideo } from './facebook-intercept-types';

const GRAPHQL_SEGMENT = '/api/graphql/';

const RE_TRAILING_SLASHES = /\/+$/;

function isFacebookUrl(url: string): boolean {
    if (!url || typeof url !== 'string') {
        return false;
    }
    try {
        const u = new URL(url, window.location.origin);
        const h = u.hostname.toLowerCase();
        return (
            h === 'facebook.com'
            || h.endsWith('.facebook.com')
            || h === 'fb.com'
            || h.endsWith('.fb.com')
            || h === 'fb.watch'
            || h.endsWith('.fb.watch')
        );
    }
    catch {
        return false;
    }
}

function normalizePathname(pathname: string | undefined): string {
    const p = (pathname ?? '/').replace(RE_TRAILING_SLASHES, '');
    return p || '/';
}

function isActivePageDocumentUrl(url: string): boolean {
    if (!isFacebookUrl(url)) {
        return false;
    }
    try {
        const req = new URL(url, window.location.origin);
        const loc = new URL(window.location.href);
        if (req.origin !== loc.origin) {
            return false;
        }
        return (
            normalizePathname(req.pathname) === normalizePathname(loc.pathname)
        );
    }
    catch {
        return false;
    }
}

function isGraphQlUrl(url: string): boolean {
    return isFacebookUrl(url) && url.includes(GRAPHQL_SEGMENT);
}

function requestUrlFromFetchArgs(
    args: Parameters<typeof window.fetch>,
): string {
    const first = args[0];
    if (typeof first === 'string') {
        return first;
    }
    if (first instanceof URL) {
        return first.href;
    }
    if (first && typeof first === 'object' && typeof first.url === 'string') {
        return first.url;
    }
    return '';
}

function scheduleBodyRead(
    response: Response,
    consume: (text: string) => void,
): void {
    void response
        .clone()
        .text()
        .then(consume)
        .catch(() => {});
}

/**
 * Idempotent: safe to call from the MAIN-world bundle entry.
 */
export function installRvdFacebookIntercept(): void {
    if (typeof window !== 'undefined' && window.__rvdFbNetIntercept) {
        return;
    }
    if (typeof window !== 'undefined') {
        window.__rvdFbNetIntercept = true;
    }

    const nativeFetch = window.fetch.bind(window);
    window.fetch = async function patchedFetch(
        ...args: Parameters<typeof window.fetch>
    ) {
        const response = await nativeFetch(...args);
        try {
            const resourceUrl = requestUrlFromFetchArgs(args);
            if (!resourceUrl || !isFacebookUrl(resourceUrl)) {
                return response;
            }
            if (isGraphQlUrl(resourceUrl)) {
                scheduleBodyRead(response, processGraphQlResponseBody);
            }
            else if (isActivePageDocumentUrl(resourceUrl)) {
                scheduleBodyRead(response, text =>
                    processDocumentResponseBody(resourceUrl, text));
            }
        }
        catch {
            /* never break fetch */
        }
        return response;
    };

    const xhrOpen = XMLHttpRequest.prototype.open;
    const xhrSend = XMLHttpRequest.prototype.send;

    XMLHttpRequest.prototype.open = function openPatched(
        method: string,
        url: string | URL,
        ...rest: unknown[]
    ) {
        this._rvdFbUrl = url;
        return xhrOpen.apply(this, [method, url, ...rest] as Parameters<
            typeof xhrOpen
        >);
    };

    XMLHttpRequest.prototype.send = function sendPatched(...sendArgs: unknown[]) {
        const url = this._rvdFbUrl;
        const urlStr
            = typeof url === 'string'
                ? url
                : url instanceof URL
                    ? url.href
                    : '';
        if (urlStr && isFacebookUrl(urlStr)) {
            if (isGraphQlUrl(urlStr)) {
                this.addEventListener('load', function onLoadGql() {
                    try {
                        processGraphQlResponseBody(this.responseText);
                    }
                    catch {
                        /* ignore */
                    }
                });
            }
            else if (isActivePageDocumentUrl(urlStr)) {
                this.addEventListener('load', function onLoadDoc() {
                    try {
                        processDocumentResponseBody(urlStr, this.responseText);
                    }
                    catch {
                        /* ignore */
                    }
                });
            }
        }
        return xhrSend.apply(this, sendArgs as Parameters<typeof xhrSend>);
    };

    function runDeferredDomPass(pageUrl: string): void {
        setTimeout(() => {
            const html = document.documentElement?.outerHTML;
            if (html && html.length > 5000) {
                processDocumentResponseBody(pageUrl, html);
            }
        }, 2500);
    }

    function bootstrapCurrentPage(): void {
        const pageUrl = window.location.href;
        if (!isFacebookUrl(pageUrl)) {
            return;
        }
        void nativeFetch(pageUrl, { credentials: 'include', redirect: 'follow' })
            .then(r => r.text())
            .then(text => processDocumentResponseBody(pageUrl, text))
            .catch(() => {});
        runDeferredDomPass(pageUrl);
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', bootstrapCurrentPage);
    }
    else {
        bootstrapCurrentPage();
    }
}
