/** GraphQL NDJSON + document/HTML → {@link WireVideo}; `postMessage` to isolated world. */

import type { WirePlayableRow, WireVideo } from './facebook-intercept-types';

interface Ctx { title?: string; author?: string; storyPermalink?: string }
const DEPTH = 52;

const VDR_KEY = 'videoDeliveryResponseResult';

const RE_FALLBACK_VIDEO_PATH = /\/videos\/(\d+)/;
const RE_WS = /\s/;
const RE_HASHTAG = /#\S+/g;

function rec(x: unknown): x is Record<string, unknown> {
    return typeof x === 'object' && x !== null && !Array.isArray(x);
}

/** Brace-balanced `{…}` ending at `anchorIndex` (string-aware); scans backward to opening `{`. */
function sliceObjBackward(s: string, anchorIndex: number): string | null {
    if (anchorIndex < 0 || anchorIndex >= s.length)
        return null;
    const a = s.lastIndexOf('{', anchorIndex);
    if (a === -1)
        return null;
    let d = 0;
    let q: string | null = null;
    let esc = false;
    for (let p = a; p < s.length; p++) {
        const c = s[p]!;
        if (esc) {
            esc = false;
            continue;
        }
        if (q) {
            if (c === '\\')
                esc = true;
            else if (c === q)
                q = null;
            continue;
        }
        if (c === '"' || c === '\'') {
            q = c;
            continue;
        }
        if (c === '{') {
            d++;
        }
        else if (c === '}') {
            if (--d === 0)
                return s.slice(a, p + 1);
        }
    }
    return null;
}

/** Brace-balanced object starting exactly at `openBrace` (must be `{`). */
function sliceBalancedObjectFrom(s: string, openBrace: number): string | null {
    if (openBrace < 0 || openBrace >= s.length || s[openBrace] !== '{')
        return null;
    let d = 0;
    let q: string | null = null;
    let esc = false;
    for (let p = openBrace; p < s.length; p++) {
        const c = s[p]!;
        if (esc) {
            esc = false;
            continue;
        }
        if (q) {
            if (c === '\\')
                esc = true;
            else if (c === q)
                q = null;
            continue;
        }
        if (c === '"' || c === '\'') {
            q = c;
            continue;
        }
        if (c === '{') {
            d++;
        }
        else if (c === '}') {
            d--;
            if (d === 0)
                return s.slice(openBrace, p + 1);
        }
    }
    return null;
}

function scanMarkers(text: string, marker: string, minLen: number, each: (obj: Record<string, unknown>) => void): void {
    const seen = new Set<string>();
    for (let idx = 0; ;) {
        const pos = text.indexOf(marker, idx);
        if (pos === -1)
            break;
        const raw = sliceObjBackward(text, pos);
        if (raw && raw.length >= minLen && !seen.has(raw)) {
            seen.add(raw);
            try {
                const o = JSON.parse(raw) as unknown;
                if (rec(o))
                    each(o);
            }
            catch { /* */ }
        }
        idx = pos + 1;
    }
}

function extractVideoNodes(html: string): Record<string, unknown>[] {
    const out: Record<string, unknown>[] = [];
    for (const m of ['"__typename":"Video"', '"__typename": "Video"']) {
        scanMarkers(html, m, 50, (o) => {
            if (o.__typename === 'Video' && o.id && o.videoDeliveryResponseFragment)
                out.push(o);
        });
    }
    return out;
}

function extractCreationStory(html: string): Record<string, unknown> | null {
    let hit: Record<string, unknown> | null = null;
    scanMarkers(html, '"creation_story":', 200, (o) => {
        if (hit)
            return;
        if (o.creation_story)
            hit = { video: { creation_story: o.creation_story } };
        else if (rec(o.video) && o.video.creation_story)
            hit = o;
        else if (Array.isArray(o.attachments) && rec(o.attachments[0]) && rec(o.attachments[0].media) && o.attachments[0].media.__typename === 'Video')
            hit = { video: { creation_story: o } };
    });
    return hit;
}

/** `/videos/{id}` from page or fetched document URL (Comet progressive slices often omit `id`). */
function fallbackVideoIdFromDocumentUrl(url: string): string | null {
    try {
        const m = new URL(url, 'https://www.facebook.com').pathname.match(RE_FALLBACK_VIDEO_PATH);
        return m?.[1] ?? null;
    }
    catch {
        return null;
    }
}

function flushPost(seen: Map<string, WireVideo>): void {
    const playable = [...seen.values()].filter(v => v.urls.length > 0);
    if (playable.length > 0)
        window.postMessage({ type: 'FB_VIDEO_DATA', videos: playable }, '*');
}

function uri(x: unknown): string {
    if (typeof x === 'string' && x)
        return x;
    if (rec(x))
        return (typeof x.uri === 'string' && x.uri) || (typeof x.url === 'string' && x.url) || '';
    return '';
}

function thumb(v: Record<string, unknown>): string {
    for (const c of [v.preferred_thumbnail, v.thumbnailImage, v.image, v.full_image, v.cover_photo, rec(v.story) ? v.story.cover_photo : undefined]) {
        const u = uri(c) || (rec(c) && c.image ? uri(c.image) : '');
        if (u)
            return u;
    }
    return '';
}

function cap(x: unknown): string {
    return typeof x === 'string' ? x : rec(x) && typeof x.text === 'string' ? x.text : '';
}

function numMd(md: unknown, keys: string[]): number | undefined {
    if (!rec(md))
        return undefined;
    for (const k of keys) {
        const v = md[k];
        if (typeof v === 'number' && Number.isFinite(v))
            return v;
    }
    return undefined;
}

function inferQualityFromDims(width?: number, height?: number): 'SD' | 'HD' {
    return Math.max(width ?? 0, height ?? 0) >= 720 ? 'HD' : 'SD';
}

function push(list: WirePlayableRow[], url: string, quality: string, dims?: Partial<Pick<WirePlayableRow, 'width' | 'height' | 'bandwidth' | 'fps'>>): void {
    const u = url.trim();
    if (!u)
        return;
    list.push({ url: u, quality, type: 'progressive', ...dims });
}

function urlsFromDelivery(d: unknown, list: WirePlayableRow[]): void {
    if (!rec(d))
        return;
    let hasHd = false;
    let hasSd = false;
    const arr = d.progressive_urls;
    if (Array.isArray(arr)) {
        for (const p of arr) {
            if (!rec(p) || p.failure_reason)
                continue;
            const link = uri(p.progressive_url);
            if (!link)
                continue;
            const md = rec(p.metadata) ? p.metadata : {};
            const w = numMd(md, ['width', 'WIDTH']) ?? (typeof p.width === 'number' ? p.width : undefined);
            const h = numMd(md, ['height', 'HEIGHT']) ?? (typeof p.height === 'number' ? p.height : undefined);
            const qRaw = typeof md.quality === 'string' ? md.quality.trim().toUpperCase() : '';
            const label: 'SD' | 'HD' = qRaw === 'SD' || qRaw === 'HD' ? qRaw : inferQualityFromDims(w, h);
            if (label === 'HD')
                hasHd = true;
            else
                hasSd = true;
            push(list, link, label, {
                width: w,
                height: h,
                bandwidth: numMd(md, ['bandwidth', 'BANDWIDTH', 'bitrate', 'BITRATE']),
                fps: numMd(md, ['frame_rate', 'frameRate', 'fps', 'FPS']),
            });
        }
    }
    const nHd = uri(d.browser_native_hd_url);
    const nSd = uri(d.browser_native_sd_url);
    if (nHd && !hasHd)
        push(list, nHd, 'HD', {});
    if (nSd && !hasSd)
        push(list, nSd, 'SD', {});
}

function toWire(v: Record<string, unknown>, ctx: Ctx): WireVideo | null {
    const frag = v.videoDeliveryResponseFragment;
    const delivery = rec(frag) ? frag.videoDeliveryResponseResult : undefined;
    if (delivery === undefined)
        return null;
    const name = v.name;
    const t0 = ctx.title ?? '';
    const t1 = typeof name === 'string' && name.trim() ? name.trim().slice(0, 200) : '';
    const desc = cap(v.video_caption) || cap(v.savable_description) || cap(v.title_text_with_entities) || '';
    const dur = v.playable_duration_in_ms
        ? Number(v.playable_duration_in_ms) / 1000
        : typeof v.length_in_second === 'number'
            ? v.length_in_second
            : typeof v.playable_duration === 'number' ? v.playable_duration : 0;
    const own = v.owner;
    const author = rec(own) && typeof own.name === 'string' ? own.name : '';
    const w: WireVideo = {
        videoId: String(v.id),
        title: t0 || t1,
        author: ctx.author || author,
        permalink: (typeof v.permalink_url === 'string' && v.permalink_url)
            || (typeof v.shareable_url === 'string' && v.shareable_url)
            || (typeof v.url === 'string' && v.url) || ctx.storyPermalink || '',
        duration: dur,
        thumbnail: thumb(v),
        description: desc ? desc.slice(0, 4000) : '',
        urls: [],
    };
    urlsFromDelivery(delivery, w.urls);
    return w.urls.length ? w : null;
}

function merge(a: WireVideo, b: WireVideo | null): void {
    if (!b)
        return;
    if (b.title && !a.title)
        a.title = b.title;
    if (b.author && !a.author)
        a.author = b.author;
    if (b.description && !a.description)
        a.description = b.description;
    if (b.thumbnail && !a.thumbnail)
        a.thumbnail = b.thumbnail;
    if (b.permalink && !a.permalink)
        a.permalink = b.permalink;
    if (b.duration > (a.duration || 0))
        a.duration = b.duration;
    const m = new Map(a.urls.map(r => [r.url, r]));
    for (const r of b.urls) m.set(r.url, r);
    a.urls = [...m.values()];
}

/** One path: delivery result object → `toWire` → `seen`. */
function mergeDeliveryResultIntoSeen(
    seen: Map<string, WireVideo>,
    delivery: Record<string, unknown>,
    fallbackVideoId: string | null,
    ctx: Ctx,
): void {
    const idRaw = delivery.id ?? delivery.video_id ?? fallbackVideoId;
    if (idRaw == null || idRaw === '')
        return;
    const id = String(idRaw);
    const min: Record<string, unknown> = {
        id,
        videoDeliveryResponseFragment: { videoDeliveryResponseResult: delivery },
    };
    try {
        const wire = toWire(min, ctx);
        if (!wire)
            return;
        const ex = seen.get(id);
        if (ex)
            merge(ex, wire);
        else
            seen.set(id, wire);
    }
    catch { /* */ }
}

function tryBareDeliveryRoot(seen: Map<string, WireVideo>, parsed: unknown, fallbackVideoId: string | null): void {
    if (!rec(parsed))
        return;
    const dr = parsed.videoDeliveryResponseResult;
    if (!rec(dr) || !Array.isArray(dr.progressive_urls) || dr.progressive_urls.length === 0)
        return;
    mergeDeliveryResultIntoSeen(seen, dr, fallbackVideoId, {});
}

/** Anchor at `videoDeliveryResponseResult` then forward-balanced `{`; avoids `progressive_urls` inside `dash_manifests`. */
function extractVideoDeliveryResultsFromHtml(html: string): Record<string, unknown>[] {
    const out: Record<string, unknown>[] = [];
    const seenJson = new Set<string>();
    let from = 0;
    for (;;) {
        const pos = html.indexOf(VDR_KEY, from);
        if (pos === -1)
            break;
        const colon = html.indexOf(':', pos + VDR_KEY.length);
        if (colon === -1 || colon - pos > 48) {
            from = pos + VDR_KEY.length;
            continue;
        }
        let j = colon + 1;
        while (j < html.length && RE_WS.test(html[j]!))
            j++;
        if (j >= html.length || html[j] !== '{') {
            from = pos + VDR_KEY.length;
            continue;
        }
        const raw = sliceBalancedObjectFrom(html, j);
        if (!raw || seenJson.has(raw)) {
            from = pos + VDR_KEY.length;
            continue;
        }
        seenJson.add(raw);
        try {
            const o = JSON.parse(raw) as unknown;
            if (rec(o) && Array.isArray(o.progressive_urls) && o.progressive_urls.length > 0)
                out.push(o);
        }
        catch { /* */ }
        from = pos + VDR_KEY.length;
    }
    return out;
}

function walk(o: unknown, ctx: Ctx, seen: Map<string, WireVideo>, depth: number): void {
    if (depth > DEPTH || !o || typeof o !== 'object')
        return;
    const x = o as Record<string, unknown>;
    const c: Ctx = { ...ctx };
    if (rec(x.message) && x.message.text && !c.title)
        c.title = String(x.message.text).split('\n')[0]!.replace(RE_HASHTAG, '').trim().slice(0, 200);
    if (rec(x.story_bucket_owner) && x.story_bucket_owner.name && !c.author)
        c.author = String(x.story_bucket_owner.name).trim();
    if (rec(x.story_card_info) && rec(x.story_card_info.permalink_info) && x.story_card_info.permalink_info.uri)
        c.storyPermalink = String(x.story_card_info.permalink_info.uri);
    if (rec(x.owner) && typeof x.owner.name === 'string')
        c.author = x.owner.name;
    else if (Array.isArray(x.actors) && rec(x.actors[0]) && x.actors[0].name && !c.author)
        c.author = String(x.actors[0].name);
    else if (!c.author && x.__typename === 'User' && typeof x.name === 'string' && x.name.trim())
        c.author = x.name.trim();

    if (x.__typename === 'Video' && x.id && x.videoDeliveryResponseFragment) {
        const id = String(x.id);
        const w = toWire(x, c);
        if (w) {
            const ex = seen.get(id);
            if (ex)
                merge(ex, w);
            else
                seen.set(id, w);
        }
    }
    const kids = Array.isArray(o) ? o : Object.values(x);
    for (const ch of kids) {
        if (ch && typeof ch === 'object')
            walk(ch, c, seen, depth + 1);
    }
}

export function processGraphQlResponseBody(body: string): void {
    if (!body)
        return;
    const seen = new Map<string, WireVideo>();
    for (const line of body.split('\n')) {
        const t = line.trim();
        if (!t || (t[0] !== '{' && t[0] !== '['))
            continue;
        if (!t.includes('Video') && !t.includes('progressive_url') && !t.includes('videoDeliveryResponseFragment') && !t.includes('videoDeliveryResponseResult') && !t.includes('unified_stories'))
            continue;
        try {
            const parsed = JSON.parse(t) as unknown;
            tryBareDeliveryRoot(seen, parsed, null);
            walk(parsed, {}, seen, 0);
        }
        catch { /* */ }
    }
    flushPost(seen);
}

export function processDocumentResponseBody(pageUrl: string, text: string): void {
    if (!text)
        return;
    const seen = new Map<string, WireVideo>();
    const fb = fallbackVideoIdFromDocumentUrl(pageUrl);
    const t = text.trim();

    if (t.startsWith('{') || t.startsWith('[')) {
        try {
            const parsed = JSON.parse(t) as unknown;
            tryBareDeliveryRoot(seen, parsed, fb);
            walk(parsed, {}, seen, 0);
        }
        catch { /* */ }
    }

    for (const d of extractVideoDeliveryResultsFromHtml(text))
        mergeDeliveryResultIntoSeen(seen, d, fb, {});

    if (t.startsWith('<!') || t.startsWith('<html') || t.includes('</html>') || (t.length > 500 && t.includes('<'))) {
        const st = extractCreationStory(text);
        if (st) {
            try {
                walk(st, {}, seen, 0);
            }
            catch { /* */ }
        }
        for (const n of extractVideoNodes(text)) {
            try {
                walk(n, {}, seen, 0);
            }
            catch { /* */ }
        }
    }

    flushPost(seen);
}
